"use client";

import { useState, useEffect } from "react";
import { Eye, Loader2, ArrowLeft } from "lucide-react";
import Link from "next/link";
import api from "@/lib/api/axios";
import { toast } from "sonner";

interface PageViewData {
  total_page_views: number;
  unique_page_views: number;
  avg_time_on_page: number;
  by_page_type: Record<string, number>;
}

export default function PageViewsPage() {
  const [data, setData] = useState<PageViewData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchPageViews();
  }, []);

  const fetchPageViews = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem("token");

      const response = await api.get("/api/admin/analytics/page-views", {
        headers: token ? { Authorization: `Bearer ${token}` } : {},
      });

      if (response.data.success) {
        const responseData = response.data.data;
        
        if (responseData && typeof responseData === 'object') {
          setData(responseData);
        } else {
          setData(null);
        }
      } else {
        setData(null);
        toast.error(response.data.message || "Failed to load page views");
      }
    } catch (error: any) {
      console.error("Error fetching page views:", error);
      setData(null);
      
      const errorMessage = error.response?.data?.message || error.message || "Failed to load page views";
      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="mb-6">
        <Link
          href="/admin/analytics"
          className="mb-4 inline-flex items-center gap-2 text-sm text-gray-600 hover:text-gray-900"
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Dashboard
        </Link>
        <div className="flex items-center gap-3">
          <div className="rounded-full bg-green-100 p-3">
            <Eye className="h-6 w-6 text-green-600" />
          </div>
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Page Views</h1>
            <p className="text-sm text-gray-500">Page traffic and engagement</p>
          </div>
        </div>
      </div>

      <div className="grid gap-6 md:grid-cols-3">
        <div className="rounded-lg bg-white p-6 shadow-sm">
          <p className="text-sm font-medium text-gray-500">Total Page Views</p>
          <p className="mt-2 text-3xl font-bold text-gray-900">{data?.total_page_views || 0}</p>
        </div>
        <div className="rounded-lg bg-white p-6 shadow-sm">
          <p className="text-sm font-medium text-gray-500">Unique Page Views</p>
          <p className="mt-2 text-3xl font-bold text-gray-900">{data?.unique_page_views || 0}</p>
        </div>
        <div className="rounded-lg bg-white p-6 shadow-sm">
          <p className="text-sm font-medium text-gray-500">Avg Time on Page</p>
          <p className="mt-2 text-3xl font-bold text-gray-900">{data?.avg_time_on_page || 0}s</p>
        </div>
      </div>

      {data?.by_page_type && Object.keys(data.by_page_type).length > 0 && (
        <div className="mt-6 rounded-lg bg-white p-6 shadow-sm">
          <h2 className="mb-4 text-lg font-semibold text-gray-900">Views by Page Type</h2>
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {Object.entries(data.by_page_type).map(([type, count]) => (
              <div key={type} className="rounded-lg border border-gray-200 p-4">
                <p className="text-sm font-medium capitalize text-gray-500">{type}</p>
                <p className="mt-2 text-2xl font-bold text-gray-900">{count}</p>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
